import{_ as n,o as t,c as i,ag as r}from"./chunks/framework.DXGyWiRo.js";const s="/images/uebung046.jpg",g=JSON.parse('{"title":"Übung Lektion 29","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung29.md","filePath":"lektionen/uebung29.md"}'),a={name:"lektionen/uebung29.md"};function u(o,e,d,h,p,l){return t(),i("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-29" tabindex="-1">Übung Lektion 29 <a class="header-anchor" href="#ubung-lektion-29" aria-label="Permalink to &quot;Übung Lektion 29&quot;">​</a></h1><p>Übersetzen Sie wortgetreu in gutes Deutsch und lernen Sie die Sanskrittexte auswendig:</p><p>1. Definition von अविद्या :</p><p>अनित्याशुचिदुःखानात्मसु नित्यशुचिसुखात्मख्यातिरविद्या ॥योगसूत्र २.५॥</p><p>Erklärung: आत्मसु = Lok. sg. zu आत्मन् m. &quot;Seele ; das Absolute, insofern es im Individuum verwirklicht wird&quot;</p><p>Unwissen bedeutet, dass man Unbeständiges, Unreines, Leidvolles und Nicht-Absolutes als beständig, rein, freudvoll bzw. absolut ansieht.</p><p>2. कौटिलीयार्थशास्त्र 1.4. über den rechten Gebrauch des दण्ड :</p><p>तीक्ष्णदण्डो भूतानामुद्वेजनीयो भवति ।८। मृदुदण्डः परिभूयते ।९। यथार्हदण्डः पूज्यते ।१०। सुविज्ञातप्रणीतो हि दण्डः प्रजा धर्मार्थकामैर्योजयति ।११। दुष्प्रणीतः कामक्रोधाभ्यामवज्ञानाद्वा वानप्रस्थपरिव्राजकानपि कोपयति, किमङ्ग पुनर्गृहस्थान् ।१२। अप्रणीतस्तु मात्स्यन्यायमुद्भावयति ।१३। बलीयानबलं हि ग्रसते दण्डधराभावे ।१४। स तेन गुप्तः प्रभवतीति ।१५।</p><blockquote><p>चतुर्वर्णाश्रमो लोको<br> राज्ञा दण्डेन पालितः ।<br> स्वधर्मकर्माभिरतो<br> वर्तते स्वेषु वर्त्मसु ॥१६॥</p></blockquote><p>Vor einem zu strengen Regiment müssen die Wesen schaudern. Ein lasches Regiment wird verachtet. Ein gerade richtiges Regiment wird verehrt. Ein weise geführtes Regiment fördert bei den Untertanen Recht, Gewinn und Lust. Ein wegen Lust und Hass oder Verachtung schlecht geführtes Regiment erzürnt selbst in den Wald zurückgezogene Alte und Wandersasketen, um wieviel mehr Hausväter. Nicht ausgeübtes Regiment bewirkt ein Verhalten wie Fische. Wenn niemand da ist, der das Regiment aufrecht erhält, verschlingt nämlich der Stärkere den Schwachen. Wenn der Schwache vom Regimentsinhaber behütet wird, gedeiht er.</p><blockquote><p>Die Welt mit ihren vier Ständen und Lebensstadien<br> Wird vom König durch das Regiment beschützt:<br> Froh über die Tätigkeit nach eigenem Recht und eigener Sitte<br> Bewegt sie sich auf ihren eigenen Bahnen.</p></blockquote><p>Erklärungen:</p><p>।८। उद्वेजनीय ३ &quot;etwas (jemand), vor dem man schaudern muss&quot;</p><p>।११। विज्ञात ३ &quot;erkannt&quot; ; n.: Erkennen</p><p>।११। योजयति (Kaus. zu युज्) &quot;anschirren, verbinden mit, vereinigen mit&quot;</p><p>।१२। कामक्रोधाभ्याम् : Instr., Dat. Abl., Dual mask. von कामक्रोध (Dualdvandva)</p><p>।१२। किमङ्ग &quot;um wieviel mehr&quot;</p><p>।१४। बलीयान् : Nom. sg. mask. zu बलीयस् ३ &quot;stärker&quot;</p><p>।१६। चतुर् &quot;vier&quot; als Vorderglied eines Kompositums</p><p>राज्ञा Instr. sg. mask. zu राजन् m. &quot;König&quot;</p><p>स्वेषु : Lok. plur. mask. / neutr. zu स्व ३ &quot;eigen (mein, dein, sein usw.)&quot;</p><p>वर्त्मसु : Lok. plur neutr. zu वर्त्मन् n. &quot;Bahn, Gleis, Pfad&quot;</p><p><img src="'+s+'" alt=""><br> Abb.: चतुर्वर्णाश्रमो लोको<br> राज्ञा दण्डेन पालितः ।<br> स्वधर्मकर्माभिरतो<br> वर्तते स्वेषु वर्त्मसु ॥१६॥<br> Dr. Raman Singh = ड. रमण सिंग, seit 2003 Chief Minister (मुख्यमंत्री) von Chhatisgarh छत्तीसगढ़ = छत्तीसगढ़<br> [Bildquelle: Amita Sharma. -- <a href="http://www.flickr.com/photos/hindibhasha/2593298459/in/set-72157605709733141/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/hindibhasha/2593298459/in/set-72157605709733141/</a>. -- Zugriff am 2008-12-29. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung)]</p>',24)])])}const c=n(a,[["render",u]]);export{g as __pageData,c as default};
